function getWrappedName(
  outerType: mixed,
  innerType: any,
  wrapperName: string,
): string {
  const functionName = innerType.displayName || innerType.name || '';
  return (
    (outerType as any).displayName ||
    (functionName !== '' ? `${wrapperName}(${functionName})` : wrapperName)
  );
}

// Keep in sync with shared/getComponentNameFromType
function getContextName(type: ReactContext<any>) {
  return type.displayName || 'Context';
}

export function getComponentNameFromOwner(
  owner: Fiber | ReactComponentInfo,
): string | null {
  if (typeof owner.tag === 'number') {
    return getComponentNameFromFiber(owner as any);
  }
  if (typeof owner.name === 'string') {
    return owner.name;
  }
  return null;
}

export function getDefaultStore(): Store {
  if (!defaultStore) {
    defaultStore = createStore()
    if (import.meta.env?.MODE !== 'production') {
      ;(
        globalThis as { __JOTAI_DEFAULT_STORE__?: unknown }
      ).__JOTAI_DEFAULT_STORE__ ||= defaultStore
      if (
        (globalThis as { __JOTAI_DEFAULT_STORE__?: unknown })
          .__JOTAI_DEFAULT_STORE__ !== defaultStore
      ) {
        console.warn(
          'Detected multiple Jotai instances. It may cause unexpected behavior with the default store. https://github.com/pmndrs/jotai/discussions/2044',
        )
      }
    }
  }
  return defaultStore
}

const createAtom = (param: Param) => {
  let item: [AtomType, CreatedAt] | undefined
  if (areEqual === undefined) {
    item = atoms.get(param)
  } else {
    // Custom comparator, iterate over all elements
    for (const [key, value] of atoms) {
      if (areEqual(key, param)) {
        item = value
        break
      }
    }
  }

  if (item !== undefined) {
    if (shouldRemove?.(item[1], param)) {
      createAtom.remove(param)
    } else {
      return item[0]
    }
  }

  const newAtom = initializeAtom(param)
  atoms.set(param, [newAtom, Date.now()])
  notifyListeners('CREATE', param, newAtom)
  return newAtom
}

export function atomWithReset<Value>(
  initialValue: Value,
): WritableAtom<Value, [SetStateActionWithReset<Value>], void> &
  WithInitialValue<Value> {
  type Update = SetStateActionWithReset<Value>
  const anAtom = atom<Value, [Update], void>(
    initialValue,
    (get, set, update) => {
      const nextValue =
        typeof update === 'function'
          ? (update as (prev: Value) => Value | typeof RESET)(get(anAtom))
          : update

      set(anAtom, nextValue === RESET ? initialValue : nextValue)
    },
  )
  return anAtom as WritableAtom<Value, [Update], void> & WithInitialValue<Value>
}

export function loadable<Value>(anAtom: Atom<Value>): Atom<Loadable<Value>> {
  if (import.meta.env?.MODE !== 'production' && !didWarnDeprecation) {
    console.warn(
      '[DEPRECATED] loadable is deprecated and will be removed in v3. ' +
        'Please use a userland util with the `unwrap` util: https://github.com/pmndrs/jotai/pull/3217',
    )
    didWarnDeprecation = true
  }
  return memo1(() => {
    const LOADING: Loadable<Value> = { state: 'loading' }
    const unwrappedAtom = unwrap(anAtom, () => LOADING)
    return atom((get) => {
      try {
        const data = get(unwrappedAtom)
        if (data === LOADING) {
          return LOADING
        }
        return { state: 'hasData', data } as Loadable<Value>
      } catch (error) {
        return { state: 'hasError', error }
      }
    })
  }, anAtom)
}

const _setValid = async (shouldUpdateValid?: boolean) => {
  if (_state.keepIsValid) {
    return;
  }
  if (
    !_options.disabled &&
    (_proxyFormState.isValid ||
      _proxySubscribeFormState.isValid ||
      shouldUpdateValid)
  ) {
    let isValid: boolean;
    if (_options.resolver) {
      isValid = isEmptyObject((await _runSchema()).errors);
      _updateIsValidating();
    } else {
      isValid = await executeBuiltInValidation({
        fields: _fields,
        onlyCheckValid: true,
        eventType: EVENTS.VALID,
      });
    }
    if (isValid !== _formState.isValid) {
      _subjects.state.next({
        isValid,
      });
    }
  }
};

const getValues: UseFormGetValues<TFieldValues> = (
  fieldNames?:
    | FieldPath<TFieldValues>
    | ReadonlyArray<FieldPath<TFieldValues>>,
  config?: GetValuesConfig,
) => {
  let values = {
    ...(_state.mount ? _formValues : _defaultValues),
  };

  if (config) {
    values = extractFormValues(
      config.dirtyFields ? _formState.dirtyFields : _formState.touchedFields,
      values,
    );
  }

  return isUndefined(fieldNames)
    ? values
    : isString(fieldNames)
      ? get(values, fieldNames)
      : fieldNames.map((name) => get(values, name));
};

const _updateIsValidating = (names?: string[], isValidating?: boolean) => {
  if (
    !_options.disabled &&
    (_proxyFormState.isValidating ||
      _proxyFormState.validatingFields ||
      _proxySubscribeFormState.isValidating ||
      _proxySubscribeFormState.validatingFields)
  ) {
    (names || Array.from(_names.mount)).forEach((name) => {
      if (name) {
        isValidating
          ? set(_formState.validatingFields, name, isValidating)
          : unset(_formState.validatingFields, name);
      }
    });

    _subjects.state.next({
      validatingFields: _formState.validatingFields,
      isValidating: !isEmptyObject(_formState.validatingFields),
    });
  }
};

const _disableForm = (disabled?: boolean) => {
  if (isBoolean(disabled)) {
    _subjects.state.next({ disabled });
    iterateFieldsByAction(
      _fields,
      (ref, name) => {
        const currentField: Field = get(_fields, name);
        if (currentField) {
          ref.disabled = currentField._f.disabled || disabled;

          if (Array.isArray(currentField._f.refs)) {
            currentField._f.refs.forEach((inputRef) => {
              inputRef.disabled = currentField._f.disabled || disabled;
            });
          }
        }
      },
      0,
      false,
    );
  }
};

const executeSchemaAndUpdateState = async (names?: InternalFieldName[]) => {
  const { errors } = await _runSchema(names);
  _updateIsValidating(names);

  if (names) {
    for (const name of names) {
      const error = get(errors, name);
      error
        ? _names.array.has(name) &&
          isObject(error) &&
          !Object.keys(error).some((key) => !Number.isNaN(Number(key)))
          ? updateFieldArrayRootError(
              _formState.errors,
              { [name]: error } as Partial<Record<string, FieldError>>,
              name,
            )
          : set(_formState.errors, name, error)
        : unset(_formState.errors, name);
    }
  } else {
    _formState.errors = errors;
  }

  return errors;
};

export function useRoute<Args extends UseRouteArgs>(
  ...args: Args
): UseRouteResult<Args> {
  const currentRouteId: keyof RouteModules = useCurrentRouteId(
    DataRouterStateHook.UseRoute,
  );
  const id: keyof RouteModules = args[0] ?? currentRouteId;

  const state = useDataRouterState(DataRouterStateHook.UseRoute);
  const route = state.matches.find(({ route }) => route.id === id);

  if (route === undefined) return undefined as UseRouteResult<Args>;
  return {
    handle: route.route.handle,
    loaderData: state.loaderData[id],
    actionData: state.actionData?.[id],
  } as UseRouteResult<Args>;
}

const WithTheme: React.FC<WithThemeOuterProps<T>> = props => {
    const theme = !IS_RSC ? React.useContext(ThemeContext) : undefined;
    const themeProp = determineTheme(props, theme);

    if (__DEV__ && themeProp === undefined) {
      const name = getComponentName(Component);
      warnOnce('withTheme', `no ThemeProvider or theme prop in scope for "${name}"`, name);
    }

    return React.createElement(Component, {
      ...props,
      theme: themeProp,
    } as React.ComponentPropsWithRef<T>);
  };

  WithTheme.displayName = `WithTheme(${getComponentName(Component)})`;

  return hoist(WithTheme, Component);

export const withArgs = <SWRType>(hook: any) => {
  return function useSWRArgs(...args: any) {
    // Get the default and inherited configuration.
    const fallbackConfig = useSWRConfig()

    // Normalize arguments.
    const [key, fn, _config] = normalize<any, any>(args)

    // Merge configurations.
    const config = mergeConfigs(fallbackConfig, _config)

    // Apply middleware
    let next = hook
    const { use } = config
    const middleware = (use || []).concat(BUILT_IN_MIDDLEWARE)
    for (let i = middleware.length; i--; ) {
      next = middleware[i](next)
    }

    return next(key, fn || config.fetcher || null, config)
  } as unknown as SWRType
}

export const middleware: Middleware =
  useSWRNext => (key_, fetcher_, config) => {
    // fetcher might be a sync function, so this should not be an async function
    const fetcher =
      fetcher_ &&
      ((...args: any[]) => {
        const [key] = serialize(key_)
        const [, , , PRELOAD] = SWRGlobalState.get(cache) as GlobalState

        if (key.startsWith(INFINITE_PREFIX)) {
          // we want the infinite fetcher to be called.
          // handling of the PRELOAD cache happens there.
          return fetcher_(...args)
        }

        const req = PRELOAD[key]
        if (isUndefined(req)) return fetcher_(...args)
        delete PRELOAD[key]
        return req
      })
    return useSWRNext(key_, fetcher, config)
  }

export function createBranchComponent<T, P extends {children?: any}, E extends Element>(
  CollectionNodeClass: CollectionNodeClass<any> | string,
  render: (props: P, ref: ForwardedRef<E>, node: Node<T>) => ReactElement | null,
  useChildren: (props: P) => ReactNode = useCollectionChildren
): (props: P & React.RefAttributes<E>) => ReactElement | null {
  let Component = ({node}) => render(node.props, node.props.ref, node);
  let Result = (forwardRef as forwardRefType)((props: P, ref: ForwardedRef<E>) => {
    let children = useChildren(props);
    return (
      useSSRCollectionNode(CollectionNodeClass, props, ref, null, children, node => (
        <Component node={node} />
      )) ?? <></>
    );
  });
  // @ts-ignore
  Result.displayName = render.name;
  return Result;
}

